import{_ as e,b as o,o as r,i as a,j as c,g as l,aB as i}from"./chunks/framework._ZAOES46.js";const m=JSON.parse('{"title":"FaQrcode 二维码","description":"","frontmatter":{},"headers":[],"relativePath":"components/pro/FaQrcode.md","filePath":"components/pro/FaQrcode.md"}'),s={name:"components/pro/FaQrcode.md"};function n(h,t,p,g,b,f){const d=o("Badge");return r(),a("div",null,[t[0]||(t[0]=c("div",{style:{display:"none"},hidden:"true","aria-hidden":"true","data-nosnippet":""},"Are you an LLM? You can read better optimized documentation at /components/pro/FaQrcode.md for this page in Markdown format",-1)),l(d,{type:"pro",text:"专业版"}),t[1]||(t[1]=i('<h1 id="faqrcode-二维码" tabindex="-1">FaQrcode 二维码 <a class="header-anchor" href="#faqrcode-二维码" aria-label="Permalink to “FaQrcode 二维码”">​</a></h1><p>生成可自定义样式和带 Logo 的二维码，支持状态显示和下载功能。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>网站/小程序分享二维码</li><li>支付二维码</li><li>名片二维码</li><li>下载链接二维码</li><li>活动报名二维码</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>value</code></td><td><code>string</code></td><td>-</td><td><strong>必需</strong>。二维码内容</td></tr><tr><td><code>size</code></td><td><code>number</code></td><td><code>200</code></td><td>二维码尺寸 (px)</td></tr><tr><td><code>errorCorrectionLevel</code></td><td><code>&#39;L&#39; | &#39;M&#39; | &#39;Q&#39; | &#39;H&#39;</code></td><td><code>&#39;H&#39;</code></td><td>容错级别，越高可添加的 Logo 越大</td></tr><tr><td><code>logo</code></td><td><code>string</code></td><td>-</td><td>Logo 图片 URL（支持本地和网络图片）</td></tr><tr><td><code>logoSize</code></td><td><code>number</code></td><td><code>0.2</code></td><td>Logo 相对二维码的比例（0-1）</td></tr><tr><td><code>logoBackgroundColor</code></td><td><code>string</code></td><td><code>&#39;#ffffff&#39;</code></td><td>Logo 背景颜色</td></tr><tr><td><code>foregroundColor</code></td><td><code>string</code></td><td><code>&#39;#000000&#39;</code></td><td>二维码前景色</td></tr><tr><td><code>backgroundColor</code></td><td><code>string</code></td><td><code>&#39;#ffffff&#39;</code></td><td>二维码背景色</td></tr><tr><td><code>status</code></td><td><code>string</code></td><td>-</td><td>状态：<code>loading</code> / <code>expired</code> / <code>scanned</code> / <code>error</code> 等</td></tr><tr><td><code>class</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>自定义 CSS 类</td></tr></tbody></table><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to “Slots”">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th></tr></thead><tbody><tr><td><code>statusRender</code></td><td>自定义状态渲染，slot props: <code>{ status: string }</code></td></tr></tbody></table><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to “Events”">​</a></h2><table tabindex="0"><thead><tr><th>事件名</th><th>参数</th><th>说明</th></tr></thead><tbody><tr><td><code>statusRender</code></td><td><code>status: string</code></td><td>状态变化时触发</td></tr></tbody></table><h2 id="exposed-methods" tabindex="-1">Exposed Methods <a class="header-anchor" href="#exposed-methods" aria-label="Permalink to “Exposed Methods”">​</a></h2><table tabindex="0"><thead><tr><th>方法名</th><th>参数</th><th>说明</th></tr></thead><tbody><tr><td><code>download</code></td><td><code>filename?: string</code></td><td>下载二维码图片，默认文件名 <code>qrcode.png</code></td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li><p><strong>容错级别选择</strong>：</p><ul><li>添加 Logo 时建议使用 <code>&#39;H&#39;</code>（最高容错）</li><li>无 Logo 时可使用 <code>&#39;M&#39;</code> 或 <code>&#39;Q&#39;</code></li></ul></li><li><p><strong>Logo 图片</strong>：</p><ul><li>支持本地导入和 URL</li><li>网络图片需确保跨域可访问</li><li>Logo 不宜过大，建议不超过二维码的 30%</li></ul></li><li><p><strong>尺寸设置</strong>：</p><ul><li><code>size</code> 控制显示尺寸</li><li>内部使用 400px 固定分辨率生成，保证清晰度</li></ul></li><li><p><strong>状态遮罩</strong>：</p><ul><li>设置 <code>status</code> 后会显示半透明遮罩层</li><li>默认仅 <code>loading</code> 状态有旋转动画</li></ul></li></ol>',14))])}const x=e(s,[["render",n]]);export{m as __pageData,x as default};
